import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * Consumes messages from the 'inventory-updates' Kafka topic and processes them idempotently.
 * Follows Kafka ecosystem patterns for consumer configuration and shutdown.
 */
public class InventoryConsumer {
    private final String bootstrapServers;
    private final String groupId;
    private final AtomicBoolean closed;
    private KafkaConsumer<String, String> consumer;

    public InventoryConsumer(String bootstrapServers, String groupId) {
        this.bootstrapServers = bootstrapServers;
        this.groupId = groupId;
        this.closed = new AtomicBoolean(false);
    }

    public void start() {
        consumer = createKafkaConsumer();
        consumer.subscribe(Collections.singletonList("inventory-updates"));

        try {
            while (!closed.get()) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(1000));
                for (ConsumerRecord<String, String> record : records) {
                    processMessage(record);
                }
                // Commit offsets after processing each batch to ensure idempotent processing
                consumer.commitSync();
            }
        } catch (WakeupException e) {
            // Ignore exception if we are shutting down
            if (!closed.get()) {
                throw e;
            }
        } finally {
            consumer.close();
        }
    }

    /**
     * Process a single inventory update message idempotently.
     * This method should be designed to handle duplicate messages gracefully.
     */
    private void processMessage(ConsumerRecord<String, String> record) {
        // Implementation for processing inventory update
        // This ensures idempotent processing of messages
        String key = record.key();
        String value = record.value();

        // Process the inventory update message
        // Idempotent processing ensures that processing the same message multiple times
        // produces the same result as processing it once
    }

    /**
     * Shutdown the consumer gracefully.
     * Can be called from a different thread.
     */
    public void shutdown() {
        closed.set(true);
        if (consumer != null) {
            consumer.wakeup();
        }
    }

    /**
     * Create a KafkaConsumer with proper configuration using ConsumerConfig constants.
     */
    private KafkaConsumer<String, String> createKafkaConsumer() {
        Properties props = new Properties();

        // Use ConsumerConfig constants for all configuration keys (not string literals)
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);

        // Disable auto-commit to ensure we control when offsets are committed
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);

        // Set auto offset reset to earliest for idempotent processing
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        return new KafkaConsumer<>(props);
    }

    public static void main(String[] args) {
        String bootstrapServers = args.length > 0 ? args[0] : "localhost:9092";
        String groupId = args.length > 1 ? args[1] : "inventory-consumer-group";

        InventoryConsumer consumer = new InventoryConsumer(bootstrapServers, groupId);

        // Handle shutdown gracefully
        Runtime.getRuntime().addShutdownHook(new Thread(consumer::shutdown));

        consumer.start();
    }
}

